module RefModule(
               input            CLK,
               input            RST, 
               input            UP,
               input            DOWN,
               output reg [3:0] CODE
               );reg [3:0]                    obf_cnt4;
   always @( posedge CLK ) begin
      if ( !RST )
        obf_cnt4 <= 4'b0000;
      else if ( UP ) 
        obf_cnt4 <= obf_cnt4 + 4'b0001;
      else if ( DOWN ) 
        obf_cnt4 <= obf_cnt4 - 4'b0001;
   end


   always @* begin
      CODE = obf_cnt4 ^ (obf_cnt4 >> 1);
   end

endmodule
